// Mock health data
const mockHealthData = {
  healthScore: 85,
  riskLevel: 'On Track',
  isClosed: false,
  isWon: false,
  lastUpdated: new Date().toLocaleString(),
  breakdown: {
    overdueTasksScore: 100,
    lastActivityScore: 100,
    closeDateScore: 100,
    stageAgingScore: 50,
    overdueTaskCount: 0,
    daysSinceLastActivity: 3,
    daysUntilClose: 45,
    daysInCurrentStage: 15
  }
};

// State management
let isLoading = false;
let isHelpExpanded = false;
let healthData = mockHealthData;
let error = null;

// DOM elements
const loadingState = document.getElementById('loadingState');
const errorState = document.getElementById('errorState');
const healthContent = document.getElementById('healthContent');
const refreshBtn = document.getElementById('refreshBtn');
const helpToggle = document.getElementById('helpToggle');
const helpContent = document.getElementById('helpContent');
const helpIcon = document.getElementById('helpIcon');
const closedBanner = document.getElementById('closedBanner');

// Initialize component
function init() {
  updateDisplay();
  bindEvents();
}

// Bind event listeners
function bindEvents() {
  refreshBtn.addEventListener('click', handleRefresh);
  helpToggle.addEventListener('click', toggleHelp);
}

// Handle refresh button click
function handleRefresh() {
  setLoading(true);

  // Simulate API call
  setTimeout(() => {
    // Randomize some values for demo
    const newData = {
      ...mockHealthData,
      healthScore: Math.floor(Math.random() * 100),
      lastUpdated: new Date().toLocaleString(),
      breakdown: {
        ...mockHealthData.breakdown,
        daysSinceLastActivity: Math.floor(Math.random() * 20),
        daysUntilClose: Math.floor(Math.random() * 60) + 10,
        daysInCurrentStage: Math.floor(Math.random() * 90)
      }
    };

    // Recalculate risk level
    if (newData.healthScore >= 75) {
      newData.riskLevel = 'On Track';
    } else if (newData.healthScore >= 50) {
      newData.riskLevel = 'Needs Attention';
    } else {
      newData.riskLevel = 'At-Risk';
    }

    healthData = newData;
    setLoading(false);
    updateDisplay();
  }, 1000);
}

// Toggle help section
function toggleHelp() {
  isHelpExpanded = !isHelpExpanded;
  helpContent.style.display = isHelpExpanded ? 'block' : 'none';
  helpIcon.innerHTML = isHelpExpanded ? '<use xlink:href="#chevronup"></use>' : '<use xlink:href="#chevrondown"></use>';
}

// Set loading state
function setLoading(loading) {
  isLoading = loading;
  loadingState.style.display = loading ? 'block' : 'none';
  healthContent.style.display = loading ? 'none' : 'block';
  refreshBtn.disabled = loading;
}

// Update display with current data
function updateDisplay() {
  if (!healthData) return;

  // Update main score
  document.getElementById('scoreValue').textContent = healthData.healthScore;
  document.getElementById('lastUpdated').textContent = `Last Updated: ${healthData.lastUpdated}`;

  // Update risk badge
  const riskBadge = document.getElementById('riskBadge');
  riskBadge.textContent = healthData.riskLevel;
  riskBadge.className = 'risk-badge ' + getRiskClass(healthData.riskLevel);

  // Update thermometer
  updateThermometer();

  // Update criteria breakdown
  updateCriteriaBreakdown();

  // Update closed banner
  updateClosedBanner();
}

// Update thermometer visualization
function updateThermometer() {
  const thermometerFill = document.getElementById('thermometerFill');
  const bulbFill = document.getElementById('bulbFill');
  const score = healthData.healthScore;
  const riskLevel = healthData.riskLevel;

  // Set fill height
  let fillHeight;
  if (riskLevel === 'On Track' || (healthData.isClosed && healthData.isWon)) {
    fillHeight = '100%';
  } else if (riskLevel === 'At-Risk' || (healthData.isClosed && !healthData.isWon)) {
    fillHeight = '0%';
  } else {
    fillHeight = score + '%';
  }

  thermometerFill.style.height = fillHeight;

  // Set colors
  const colorClass = getColorClass(riskLevel);
  thermometerFill.className = 'thermometer-fill ' + colorClass;
  bulbFill.className = 'bulb-fill ' + colorClass;

  // Update aria attributes
  thermometerFill.setAttribute('aria-valuenow', score);
}

// Update criteria breakdown
function updateCriteriaBreakdown() {
  const breakdown = healthData.breakdown;

  // Overdue Tasks
  updateCriteriaItem('overdueTasksCard', 'overdueTasksBar', 'overdueTasksText', 'overdueTasksScore', 
    breakdown.overdueTasksScore, getOverdueTasksText(breakdown.overdueTaskCount));

  // Last Activity
  updateCriteriaItem('lastActivityCard', 'lastActivityBar', 'lastActivityText', 'lastActivityScore',
    breakdown.lastActivityScore, `Days since last activity: ${breakdown.daysSinceLastActivity}`);

  // Close Date
  updateCriteriaItem('closeDateCard', 'closeDateBar', 'closeDateText', 'closeDateScore',
    breakdown.closeDateScore, `Days until close: ${breakdown.daysUntilClose}`);

  // Stage Aging
  updateCriteriaItem('stageAgingCard', 'stageAgingBar', 'stageAgingText', 'stageAgingScore',
    breakdown.stageAgingScore, `Days in current stage: ${breakdown.daysInCurrentStage}`);
}

// Update individual criteria item
function updateCriteriaItem(cardId, barId, textId, scoreId, score, text) {
  const card = document.getElementById(cardId);
  const bar = document.getElementById(barId);
  const textEl = document.getElementById(textId);
  const scoreEl = document.getElementById(scoreId);

  // Update card class
  card.className = 'criteria-item ' + getCriteriaCardClass(score);

  // Update bar
  bar.style.width = score + '%';
  bar.className = 'score-bar ' + getScoreBarClass(score);

  // Update text and score
  textEl.textContent = text;
  scoreEl.textContent = score + '/100';
}

// Update closed banner
function updateClosedBanner() {
  if (healthData.isClosed) {
    const status = healthData.isWon ? 'Closed Won' : 'Closed Lost';
    document.getElementById('closedStatusText').textContent = `This opportunity is ${status}`;
    closedBanner.style.display = 'block';
  } else {
    closedBanner.style.display = 'none';
  }
}

// Helper functions
function getRiskClass(riskLevel) {
  switch (riskLevel) {
    case 'On Track': return 'on-track';
    case 'Needs Attention': return 'needs-attention';
    case 'At-Risk': return 'at-risk';
    default: return '';
  }
}

function getColorClass(riskLevel) {
  switch (riskLevel) {
    case 'On Track': return 'green';
    case 'Needs Attention': return 'orange';
    case 'At-Risk': return 'red';
    default: return '';
  }
}

function getScoreBarClass(score) {
  if (score >= 75) return 'green';
  if (score >= 50) return 'orange';
  return 'red';
}

function getCriteriaCardClass(score) {
  if (score >= 75) return 'on-track';
  if (score >= 50) return 'needs-attention';
  return 'at-risk';
}

function getOverdueTasksText(count) {
  if (count === 0) return 'No overdue tasks';
  if (count === 1) return '1 overdue task';
  return count + ' overdue tasks';
}

// Initialize when DOM is ready
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', init);
} else {
  init();
}

